import liStep from '@/components/li-step/li-step.vue';
import tTable from '@/components/t-table/t-table.vue';
import tTh from '@/components/t-table/t-th.vue';
import tTr from '@/components/t-table/t-tr.vue';
import tTd from '@/components/t-table/t-td.vue';
export default {
	components: {
		liStep,
		tTable,
		tTh,
		tTr,
		tTd
	},
	data() {
		return {
			tableList1:[],
			borderColor:'#fff',
			tableList: [],
			customerData:''
		};
	},
	onLoad(option) {
		this.crp_id = option.crp_id;
		this.getDetail();
	},
	computed:{
		allPayMoney:{
			get(){
				let  all= 0;
				if(this.customerData.payData){
					this.customerData.payData.forEach(res =>{
					   all =  all+ parseFloat(res.allmoney)
					})
					return all;
				}else{
					return all;
				}
			     
			},
			set(values){
				// console.log(values);
			}
		}
	},
	methods:{
		getDetail(){
			uni.showLoading({
				title:'正在加载数据...'
			})
			this.$api.getOverdueinfocustomapi({crp_id:this.crp_id},res =>{
				this.customerData = res.data;
			})
		}
	}
};
